mapper.insert:
INSERT INTO image       /* 이미지 테이블 */
(
    obj_id              /* 대상 ID */
  , obj_type            /* 대상 타입 */
  , file_key            /* 파일 키 */
  , file_url            /* 파일 URL */
  , created_at          /* 등록 일시 */
)
VALUES
(
    #{objId}
  , #{objType}
  , #{fileKey}
  , #{fileUrl}
  , NOW()
)

mapper.update:
UPDATE image        /* 이미지 테이블 */
   SET file_key = #{fileKey}           /* 파일 키 */
     , file_url = #{fileUrl}           /* 파일 URL */
 WHERE obj_type = #{objType}
   AND obj_id = #{objId}

mapper.delete:
DELETE
  FROM image        /* 이미지 테이블 */
 WHERE image_id = #{imageId}
